return [{
  json: {
    body: {
      job_id: 'test-job-' + Date.now(),
      scenes: [{
        scene_number: 1,
        class_name: 'TestScene',
        code: 'from manim import *\nclass TestScene(Scene):\n    def construct(self):\n        t = Text("Hello Physics!", font_size=48)\n        self.play(Write(t))\n        self.wait(2)\n        self.play(FadeOut(t))'
      }],
      elevenlabs_audio_url: 'https://example.com/test-audio.mp3',
      heygen_avatar_url: null
    }
  }
}];

const raw=$input.first().json;
const body=(raw.body!==undefined)?raw.body:raw;
if(!body.job_id)throw new Error("Payload missing: job_id");
if(!Array.isArray(body.scenes)||body.scenes.length===0)throw new Error("Payload missing or empty: scenes");
return[{json:{job_id:body.job_id,scenes:body.scenes,start_time:body.start_time||Date.now(),total_scenes:body.scenes.length,sheet_row:body.sheet_row||null}}];

// Render each scene then immediately mix with its own audio.
// This gives perfect sync: each scene's narration plays during that exact scene.
const { execSync } = require('child_process');
const fs   = require('fs');
const path = require('path');

const data   = $input.first().json;
const job_id = data.job_id;
const scenes = data.scenes;

const mixedPaths = [];  // final per-scene mixed video paths (inside container)
const failed     = [];

for (const scene of scenes) {
  const class_name     = scene.class_name;
  const code           = scene.code;
  const audioCont      = scene.audio_path_cont;  // already saved by Stage 1
  const audioN8n       = scene.audio_path_n8n;
  const scriptDir      = '/data/manim/scripts';
  const scriptPath     = path.join(scriptDir, class_name + '.py');

  // 1. Sanitize code â€” fix common Gemini-generated Manim errors before writing
  function sanitize(src) {
    // BROWN / DARK_BROWN â€” not defined in Manim palette
    src = src.replace(/\bBROWN\b/g, '"#A0522D"');
    src = src.replace(/\bDARK_BROWN\b/g, '"#6B3A2A"');
    // Sphere â€” 3D only; replace with Circle (extract radius if present)
    src = src.replace(/\bSphere\s*\(([^)]{0,200})\)/g, (m, args) => {
      const rm = args.match(/radius\s*=\s*([\d.]+)/);
      const r  = rm ? rm[1] : '1.5';
      return `Circle(radius=${r}, color=BLUE_E, fill_opacity=0.8)`;
    });
    // uv_resolution (Sphere param) â†’ remove if still present
    src = src.replace(/,?\s*uv_resolution\s*=\s*\([^)]+\)/g, '');
    // Star(num_points=N â†’ Star(n=N
    src = src.replace(/\bStar\s*\(\s*num_points\s*=/g, 'Star(n=');
    // Invalid rate functions â†’ smooth
    src = src.replace(/\bease_out_quad\b/g, 'smooth');
    src = src.replace(/\bease_in_quad\b/g, 'smooth');
    src = src.replace(/\bease_out_sine\b/g, 'smooth');
    src = src.replace(/\bease_in_sine\b/g, 'smooth');
    src = src.replace(/\bease_in_out_sine\b/g, 'smooth');
    // Cube (3D) â†’ RoundedRectangle
    src = src.replace(/\bCube\s*\(([^)]{0,200})\)/g, (m, args) => {
      const sm = args.match(/side_length\s*=\s*([\d.]+)/);
      const s  = sm ? sm[1] : '1.0';
      return `RoundedRectangle(width=${s}, height=${s}, corner_radius=0.1, fill_opacity=0.8)`;
    });
    return src;
  }
  const sanitizedCode = sanitize(code);

  // Write Python script
  if (!fs.existsSync(scriptDir)) fs.mkdirSync(scriptDir, { recursive: true });
  fs.writeFileSync(scriptPath, sanitizedCode, 'utf-8');

  // 2. Render with Manim (up to 3 attempts)
  let renderPath    = null;
  let renderSuccess = false;
  let renderStdout  = '';

  for (let attempt = 0; attempt < 3; attempt++) {
    let stdout = '', exitCode = 0;
    try {
      stdout = execSync(
        `docker exec manim-runner bash -c 'timeout 600 manim -qh /manim/scripts/${class_name}.py ${class_name} --media_dir /manim/renders/${job_id} 2>&1; EXIT=$?; find /manim/renders/${job_id} -name "${class_name}.mp4" -type f | tail -1; exit $EXIT'`,
        { encoding: 'utf-8', timeout: 620000 }
      );
    } catch(err) {
      stdout   = (err.stdout || err.message || '').toString();
      exitCode = err.status || 1;
    }
    const lines   = stdout.trim().split('\n').map(l => l.trim()).filter(Boolean);
    const lastLine = lines[lines.length - 1] || '';
    renderStdout  = stdout.slice(-400);
    if (lastLine.endsWith('.mp4') && exitCode === 0) {
      renderPath    = lastLine;
      renderSuccess = true;
      break;
    }
    if (attempt < 2) try { execSync('sleep 5', { timeout: 10000 }); } catch(e) {}
  }

  if (!renderSuccess) {
    const errSnippet = renderStdout.slice(-800);
    failed.push(class_name + ' | ERROR: ' + errSnippet);
    console.warn('Scene FAILED: ' + class_name + '\n--- Manim output (last 800 chars) ---\n' + errSnippet);
    continue;
  }

  // 3. Get actual video duration
  let videoDuration = 0;
  try {
    const vDurOut = execSync(
      `docker exec manim-runner bash -c 'ffprobe -v error -show_entries format=duration -of csv=p=0 "${renderPath}"'`,
      { encoding: 'utf-8', timeout: 15000 }
    );
    videoDuration = parseFloat(vDurOut.trim()) || 0;
  } catch(e) { console.warn('video ffprobe failed: ' + e.message); }

  // 4. Get exact audio duration (passed from Stage 1, or measure it now)
  let audioDuration = scene.audio_duration_seconds || 0;
  if (!audioDuration && audioCont && fs.existsSync(audioN8n)) {
    try {
      const aDurOut = execSync(
        `docker exec manim-runner bash -c 'ffprobe -v error -show_entries format=duration -of csv=p=0 "${audioCont}"'`,
        { encoding: 'utf-8', timeout: 15000 }
      );
      audioDuration = parseFloat(aDurOut.trim()) || 0;
    } catch(e) { console.warn('audio ffprobe failed: ' + e.message); }
  }

  console.log('Scene ' + scene.scene_number + ': video=' + videoDuration.toFixed(2) + 's audio=' + audioDuration.toFixed(2) + 's');

  // 5. Pad video to match audio duration (freeze last frame if video is shorter)
  let finalRenderPath = renderPath;
  if (audioDuration > 0 && videoDuration > 0 && videoDuration < audioDuration - 0.3) {
    const padSec = (audioDuration - videoDuration + 0.1).toFixed(2);
    const paddedPath = `/manim/renders/${job_id}/padded_${class_name}.mp4`;
    let padOut = '';
    try {
      padOut = execSync(
        `docker exec manim-runner bash -c 'ffmpeg -y -i "${renderPath}" -vf "tpad=stop_mode=clone:stop_duration=${padSec}" -an "${paddedPath}" 2>&1 && echo "PAD_OK"'`,
        { encoding: 'utf-8', timeout: 120000 }
      );
    } catch(e) { padOut = (e.stdout || e.message || '').toString(); }
    if (padOut.includes('PAD_OK')) {
      console.log('Padded scene ' + scene.scene_number + ' by +' + padSec + 's â†’ now matches audio');
      finalRenderPath = paddedPath;
    } else {
      console.warn('Padding failed, using original. ' + padOut.slice(-150));
    }
  } else if (audioDuration > 0 && videoDuration > audioDuration + 0.5) {
    // Trim if video is longer than audio
    const trimPath = `/manim/renders/${job_id}/trimmed_${class_name}.mp4`;
    let trimOut = '';
    try {
      trimOut = execSync(
        `docker exec manim-runner bash -c 'ffmpeg -y -i "${renderPath}" -t ${audioDuration.toFixed(3)} -c copy "${trimPath}" 2>&1 && echo "TRIM_OK"'`,
        { encoding: 'utf-8', timeout: 60000 }
      );
    } catch(e) { trimOut = (e.stdout || e.message || '').toString(); }
    if (trimOut.includes('TRIM_OK')) {
      console.log('Trimmed scene ' + scene.scene_number + ' to ' + audioDuration.toFixed(2) + 's');
      finalRenderPath = trimPath;
    }
  }

  // 6. Mix scene video + audio, locked to exact audio duration
  const mixedCont = `/manim/combined/${job_id}_scene${scene.scene_number}_mixed.mp4`;
  const mixedN8n  = `/data/manim/combined/${job_id}_scene${scene.scene_number}_mixed.mp4`;

  if (audioCont && fs.existsSync(audioN8n)) {
    const durationFlag = audioDuration > 0 ? `-t ${audioDuration.toFixed(3)}` : '-shortest';
    let mixOut = '';
    try {
      mixOut = execSync(
        `docker exec manim-runner bash -c 'ffmpeg -y -i "${finalRenderPath}" -i "${audioCont}" -c:v libx264 -preset fast -crf 18 -c:a aac -b:a 192k ${durationFlag} "${mixedCont}" 2>&1 && echo "MIX_OK"'`,
        { encoding: 'utf-8', timeout: 180000 }
      );
    } catch(err) {
      mixOut = (err.stdout || err.message || '').toString();
    }
    if (!mixOut.includes('MIX_OK')) {
      console.warn('Mix failed for scene ' + scene.scene_number + ', using silent video.\n' + mixOut.slice(-200));
      mixedPaths.push(finalRenderPath);
      continue;
    }
    console.log('Mixed scene ' + scene.scene_number + ' â†’ ' + mixedCont);
  } else {
    // No audio: re-encode video only so all scenes have compatible codec for concat
    let reencOut = '';
    try {
      reencOut = execSync(
        `docker exec manim-runner bash -c 'ffmpeg -y -i "${finalRenderPath}" -c:v libx264 -preset fast -crf 18 -an "${mixedCont}" 2>&1 && echo "REENC_OK"'`,
        { encoding: 'utf-8', timeout: 120000 }
      );
    } catch(e) { reencOut = (e.stdout || e.message || '').toString(); }
    if (!reencOut.includes('REENC_OK')) {
      console.warn('Re-encode failed for scene ' + scene.scene_number + ', using original.');
      mixedPaths.push(finalRenderPath);
      continue;
    }
    console.warn('No audio for scene ' + scene.scene_number + ', using video only.');
  }

  // 7. Apply fade-in (0.4s) + fade-out (0.4s) transitions for smooth scene cuts
  const fadedCont = `/manim/combined/${job_id}_scene${scene.scene_number}_faded.mp4`;
  const fadeDur   = 0.4;
  const sceneLen  = audioDuration > 0 ? audioDuration : videoDuration;
  const fadeOutAt = Math.max(0, sceneLen - fadeDur - 0.05).toFixed(3);
  let fadeOut = '';
  try {
    fadeOut = execSync(
      `docker exec manim-runner bash -c 'ffmpeg -y -i "${mixedCont}" ` +
      `-vf "fade=t=in:st=0:d=${fadeDur},fade=t=out:st=${fadeOutAt}:d=${fadeDur}" ` +
      `-af "afade=t=in:st=0:d=${fadeDur},afade=t=out:st=${fadeOutAt}:d=${fadeDur}" ` +
      `-c:v libx264 -preset fast -crf 18 -c:a aac -b:a 192k "${fadedCont}" 2>&1 && echo "FADE_OK"'`,
      { encoding: 'utf-8', timeout: 180000 }
    );
  } catch(e) { fadeOut = (e.stdout || e.message || '').toString(); }

  if (fadeOut.includes('FADE_OK')) {
    mixedPaths.push(fadedCont);
    console.log('Scene ' + scene.scene_number + ' faded âœ“ (fade ' + fadeDur + 's in/out)');
  } else {
    console.warn('Fade failed for scene ' + scene.scene_number + ', using mixed.\n' + fadeOut.slice(-120));
    mixedPaths.push(mixedCont);
  }
}

if (mixedPaths.length === 0) {
  throw new Error('All scenes failed.\n\n' + failed.join('\n\n'));
}
if (failed.length > 0) {
  console.warn('Skipped failed scenes: ' + failed.join(', '));
}

return [{
  json: {
    job_id,
    successful_paths: mixedPaths,
    failed_count:     failed.length,
    start_time:       data.start_time,
    total_scenes:     data.total_scenes
  }
}];

const data  = $input.first().json;
const paths = data.successful_paths;
if (!paths || paths.length === 0) throw new Error('No mixed scene paths to concatenate');

// paths are already mixed (video+audio per scene) â€” just concat them
const concatLines       = paths.map(p => `file '${p}'`).join('\n');
const concatB64         = Buffer.from(concatLines).toString('base64');
const concatInContainer = `/manim/combined/${data.job_id}_concat.txt`;
const outputInContainer = `/manim/combined/${data.job_id}_final.mp4`;
const outputInN8n       = `/data/manim/combined/${data.job_id}_final.mp4`;

return [{
  json: {
    ...data,
    concat_b64:          concatB64,
    concat_in_container: concatInContainer,
    output_in_container: outputInContainer,
    output_in_n8n:       outputInN8n,
    output_filename:     `${data.job_id}_final.mp4`
  }
}];

const { execSync } = require('child_process');
const item = $input.first().json;

let stdout = '';
try {
  stdout = execSync(
    `docker exec manim-runner bash -c 'mkdir -p /manim/combined && echo "${item.concat_b64}" | base64 -d > ${item.concat_in_container} && echo "CONCAT_FILE_OK"'`,
    { encoding: 'utf-8', timeout: 30000 }
  );
} catch (err) {
  throw new Error('Failed to write concat file: ' + (err.stdout || err.message));
}

if (!stdout.includes('CONCAT_FILE_OK')) {
  throw new Error('Concat file write did not confirm. Output: ' + stdout);
}

return [{ json: item }];

const { execSync } = require('child_process');
const item = $input.first().json;

let stdout = '';
try {
  stdout = execSync(
    `docker exec manim-runner bash -c 'timeout 900 ffmpeg -y -f concat -safe 0 -i ${item.concat_in_container} -c copy ${item.output_in_container} 2>&1 && echo "CONCAT_SUCCESS" || echo "CONCAT_FAILED"'`,
    { encoding: 'utf-8', timeout: 920000 }
  );
} catch (err) {
  stdout = (err.stdout || err.message || '').toString();
}

if (stdout.includes('CONCAT_FAILED') || !stdout.includes('CONCAT_SUCCESS')) {
  throw new Error('FFmpeg concat failed.\n' + stdout.slice(-600));
}

return [{ json: item }];

// Download audio from ElevenLabs/Drive URL and mix with animation using FFmpeg
const { execSync } = require('child_process');
const item = $input.first().json;

const audioUrl      = item.elevenlabs_audio_url;
const audioPath     = `/manim/combined/${item.job_id}_audio.mp3`;
const animPath      = item.output_in_container;
const finalPath     = `/manim/combined/${item.job_id}_final.mp4`;
const finalInN8n    = `/data/manim/combined/${item.job_id}_final.mp4`;
const finalFilename = `${item.job_id}_final.mp4`;

// Step 1: download audio
let out = '';
try {
  out = execSync(
    `docker exec manim-runner bash -c 'curl -sL "${audioUrl}" -o ${audioPath} && echo "AUDIO_OK"'`,
    { encoding: 'utf-8', timeout: 60000 }
  );
} catch(err) {
  throw new Error('Audio download failed: ' + (err.stdout || err.message));
}
if (!out.includes('AUDIO_OK')) throw new Error('Audio download did not confirm. Output: ' + out);

// Step 2: mix video + audio with FFmpeg
let mix = '';
try {
  mix = execSync(
    `docker exec manim-runner bash -c 'ffmpeg -y -i ${animPath} -i ${audioPath} -c:v copy -c:a aac -shortest ${finalPath} 2>&1 && echo "MIX_OK"'`,
    { encoding: 'utf-8', timeout: 120000 }
  );
} catch(err) {
  mix = (err.stdout || err.message || '').toString();
}
if (!mix.includes('MIX_OK')) throw new Error('FFmpeg audio mix failed:\n' + mix.slice(-600));

return [{
  json: {
    ...item,
    output_in_n8n:   finalInN8n,
    output_filename: finalFilename
  }
}];

const fs   = require('fs');
const item = $input.first().json;
const filePath = item.output_in_n8n;

if (!fs.existsSync(filePath)) {
  throw new Error('Final video not found at: ' + filePath);
}

const buffer = fs.readFileSync(filePath);

return [{
  json: item,
  binary: {
    data: {
      data:          buffer.toString('base64'),
      mimeType:      'video/mp4',
      fileName:      item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode  = $('Upload Animation to Drive').first().json;
const concatData = $('Build FFmpeg Concat').first().json;
const fileId     = driveNode.id;

const animationUrl   = `https://drive.google.com/uc?export=download&id=${fileId}`;
const renderTimeSec  = Math.round((Date.now() - concatData.start_time) / 1000);

return [{
  json: {
    job_id:               concatData.job_id,
    manim_video_url:      animationUrl,
    drive_file_id:        fileId,
    render_time_seconds:  renderTimeSec,
    elevenlabs_audio_url: concatData.elevenlabs_audio_url,
    heygen_avatar_url:    concatData.heygen_avatar_url,
    status:               'stage2_complete'
  }
}];
